// ---- helpers (small enough to live in the templ file) ----

func placementCountLabel(n int) string {
	if n == 1 {
		return "1 placement"
	}
	return fmt.Sprintf("%d placements", n)
}

func levelPaletteCols(e LevelEntityPaletteEntry) int32 {
	if e.AtlasCols <= 0 {
		return 1
	}
	return e.AtlasCols
}

func levelPaletteTileSize(e LevelEntityPaletteEntry) int32 {
	if e.TileSize <= 0 {
		return 32
	}
	return e.TileSize
}

// levelPaletteThumbStyle slices the source PNG to the entry's atlas
// cell — same math as mapmaker's paletteThumbStyle, kept as a
// separate function so future changes to one don't accidentally
// affect the other.
func levelPaletteThumbStyle(e LevelEntityPaletteEntry) string {
	if e.SpriteURL == "" {
		// Class-colored placeholder so logic entities (no sprite)
		// still show *something* in the palette.
		return "background: var(--bx-line, rgba(255,255,255,0.08));"
	}
	cols := int(levelPaletteCols(e))
	idx := int(e.AtlasIndex)
	col := idx % cols
	row := idx / cols
	thumb := 32
	totalW := thumb * cols
	return fmt.Sprintf(
		"background-image:url('%s');background-repeat:no-repeat;background-size:%dpx auto;background-position:-%dpx -%dpx;",
		e.SpriteURL, totalW, col*thumb, row*thumb,
	)
}

func levelPaletteIndentStyle(depth int) string {
	if depth <= 0 {
		return ""
	}
	return fmt.Sprintf("margin-left: %dpx;", depth*8)
}

// levelPaletteFoldersWithParent filters the flat folder list to those
// whose ParentID matches `parentID` (nil = root). Folder trees in
// Boxland are shallow (≤3 levels in practice) so a linear filter at
// each recursion level is fine.
func levelPaletteFoldersWithParent(all []folders.Folder, parentID *int64) []folders.Folder {
	var out []folders.Folder
	for _, f := range all {
		if (parentID == nil && f.ParentID == nil) ||
			(parentID != nil && f.ParentID != nil && *f.ParentID == *parentID) {
			out = append(out, f)
		}
	}
	return out
}

// levelPaletteEntriesInFolder filters palette entries to those in a
// given folder (nil = unfoldered, top-of-list).
func levelPaletteEntriesInFolder(all []LevelEntityPaletteEntry, folderID *int64) []LevelEntityPaletteEntry {
	var out []LevelEntityPaletteEntry
	for _, e := range all {
		if (folderID == nil && e.FolderID == nil) ||
			(folderID != nil && e.FolderID != nil && *e.FolderID == *folderID) {
			out = append(out, e)
		}
	}
	return out
}

// foldRefID returns &id — needed because Go disallows taking the
// address of a struct field through a range copy directly inside a
// templ expression. (Trivial helper that keeps the templ readable.)
func foldRefID(id int64) *int64 { return &id }

var _ = templruntime.GeneratedTemplate
